def solve(s):
    n = len(s)
    MOD = (1 << 61) - 1
    BASE = 31

    def check(length):
        h = 0; power = 1
        for c in s[:length]:
            h = (h * BASE + ord(c) - ord('a') + 1) % MOD
        power = pow(BASE, length, MOD)
        seen = {h: [0]}
        for i in range(1, n - length + 1):
            h = (h * BASE - (ord(s[i-1]) - ord('a') + 1) * power + ord(s[i+length-1]) - ord('a') + 1) % MOD
            if h in seen:
                curr = s[i:i+length]
                for prev in seen[h]:
                    if s[prev:prev+length] == curr:
                        return curr
                seen[h].append(i)
            else:
                seen[h] = [i]
        return ''

    lo, hi = 1, n - 1
    res = ''
    while lo <= hi:
        mid = (lo + hi) // 2
        dup = check(mid)
        if dup:
            res = dup; lo = mid + 1
        else:
            hi = mid - 1
    return res

